/**
 * @typedef {Object} ImageTextToTextOutput
 * @property {string} generated_text The generated text.
 *
 * @callback ImageTextToTextPipelineCallback Generate text based on an input image and text prompt.
 * @param {ImagePipelineInputs} images The input image(s).
 * @param {string|string[]} text The text prompt(s) to condition generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image text to text pipeline using any `AutoModelForImageTextToText`.
 * This pipeline generates text from an input image and a text prompt.
 *
 * **Example:** Generate a response based on an image w/ `onnx-community/SmolVLM-256M-Instruct`.
 * ```javascript
 * const generator = await pipeline('image-text-to-text', 'onnx-community/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await generator(url, 'Describe the image in one sentence.');
 * // [{ generated_text: 'Two cats are sitting on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Use the multimodal processor to handle both image and text inputs together
        const inputs = await this.processor(
            isBatched ? preparedImages : preparedImages[0],
            isBatched ? text : text,
            isBatched ? { padding: true } : {},
        );

        const outputIds = await this.model.generate({ ...inputs, ...generate_kwargs });

        // Causal LM output includes the input prompt tokens; slice them off to get only new tokens
        const inputLength = inputs.input_ids.dims[1];
        const newIds = /** @type {Tensor} */(outputIds).slice(null, [inputLength, null]);

        const decoded = this.processor.batch_decode(newIds, {
            skip_special_tokens: true,
        });

        const toReturn = decoded.map(x => ({ generated_text: x.trim() }));

    "pipeline": ImageToTextPipeline,
    "model": AutoModelForVision2Seq,
